1	import './style.css';
2	
3	const SVG_NS = 'http://www.w3.org/2000/svg';
4	const MIN_WIDTH = 1;
5	const MAX_WIDTH = 200;
6	const BRUSH_STRENGTH = 2;
7	const SAMPLE_MIN_DIST = 1.5;
8	const MAX_HISTORY = 50;
9	const FILE_VERSION = 1;
10	
11	type Tool = 'pen' | 'width' | 'select';
12	type RenderMode = 'catmull' | 'quadratic';
13	type Point = { x: number; y: number };
14	type Sample = Point & { w: number };
15	type Stroke = { color: string; samples: Sample[]; el: SVGPathElement; renderMode: RenderMode };
16	type Snapshot = { color: string; samples: Sample[]; renderMode: RenderMode }[];
17	type HandleHit = { stroke: Stroke; index: number };
18	type NodeDrag = {
19	  stroke: Stroke;
20	  index: number;
21	  origPositions: Point[];
22	  arcDists: number[];
23	  startPoint: Point;
24	};
25	
26	const svg = document.getElementById('canvas') as unknown as SVGSVGElement;
27	const widthInput = document.getElementById('width') as HTMLInputElement;
28	const brushInput = document.getElementById('brush') as HTMLInputElement;
29	const colorInput = document.getElementById('color') as HTMLInputElement;
30	const clearBtn = document.getElementById('clear') as HTMLButtonElement;
31	const exportBtn = document.getElementById('export') as HTMLButtonElement;
32	const saveBtn = document.getElementById('save') as HTMLButtonElement;
33	const loadBtn = document.getElementById('load') as HTMLButtonElement;
34	const toolPenBtn = document.getElementById('tool-pen') as HTMLButtonElement;
35	const toolWidthBtn = document.getElementById('tool-width') as HTMLButtonElement;
36	const toolSelectBtn = document.getElementById('tool-select') as HTMLButtonElement;
37	const undoBtn = document.getElementById('undo') as HTMLButtonElement;
38	const redoBtn = document.getElementById('redo') as HTMLButtonElement;
39	const brushCursor = document.getElementById('brush-cursor') as HTMLDivElement;
40	const selectionRect = document.getElementById('selection-rect') as HTMLDivElement;
41	const strokeOptions = document.getElementById('stroke-options') as HTMLDivElement;
42	const renderModeRadios = document.querySelectorAll<HTMLInputElement>('input[name="render-mode"]');
43	
44	const state = {
45	  tool: 'pen' as Tool,
46	  strokes: [] as Stroke[],
47	  current: null as Stroke | null,
48	  brushing: false,
49	  selected: null as Stroke | null,
50	  dragging: false,
51	  dragLast: null as Point | null,
52	  draggingNode: null as NodeDrag | null,
53	  baseWidth: Number(widthInput.value),
54	  brushRadius: Number(brushInput.value),
55	  color: colorInput.value,
56	};
57	
58	const undoStack: Snapshot[] = [];
59	const redoStack: Snapshot[] = [];
60	const handleByEl = new Map<SVGCircleElement, HandleHit>();
61	let handleGroup: SVGGElement | null = null;
62	
63	main();
64	
65	function main() {
66	  syncCanvasSize();
67	  window.addEventListener('resize', syncCanvasSize);
68	
69	  widthInput.addEventListener('input', () => {
70	    state.baseWidth = Number(widthInput.value);
71	  });
72	  brushInput.addEventListener('input', () => {
73	    state.brushRadius = Number(brushInput.value);
74	  });
75	  colorInput.addEventListener('input', () => {
76	    state.color = colorInput.value;
77	  });
78	  clearBtn.addEventListener('click', clearAll);
79	  exportBtn.addEventListener('click', exportSvg);
80	  saveBtn.addEventListener('click', saveFile);
81	  loadBtn.addEventListener('click', loadFile);
82	  toolPenBtn.addEventListener('click', () => setTool('pen'));
83	  toolWidthBtn.addEventListener('click', () => setTool('width'));
84	  toolSelectBtn.addEventListener('click', () => setTool('select'));
85	  undoBtn.addEventListener('click', undo);
86	  redoBtn.addEventListener('click', redo);
87	  renderModeRadios.forEach((r) => r.addEventListener('change', onRenderModeChange));
88	
89	  document.addEventListener('keydown', onKeyDown);
90	
91	  svg.addEventListener('pointerdown', onPointerDown);
92	  svg.addEventListener('pointermove', onPointerMove);
93	  svg.addEventListener('pointerup', onPointerUp);
94	  svg.addEventListener('pointercancel', onPointerUp);
95	  svg.addEventListener('pointerleave', () => {
96	    brushCursor.style.display = 'none';
97	  });
98	}
99	
100	function onPointerDown(e: PointerEvent) {
101	  svg.setPointerCapture(e.pointerId);
102	  if (state.tool === 'pen') penDown(e);
103	  else if (state.tool === 'width') widthDown(e);
104	  else selectDown(e);
105	}
106	
107	function onPointerMove(e: PointerEvent) {
108	  updateBrushCursor(e);
109	  if (state.tool === 'pen') penMove(e);
110	  else if (state.tool === 'width') widthMove(e);
111	  else selectMove(e);
112	}
113	
114	function onPointerUp(e: PointerEvent) {
115	  if (svg.hasPointerCapture(e.pointerId)) svg.releasePointerCapture(e.pointerId);
116	  state.current = null;
117	  state.brushing = false;
118	  selectUp();
119	}
120	
121	function onKeyDown(e: KeyboardEvent) {
122	  if (e.target instanceof HTMLInputElement) return;
123	  const mod = e.metaKey || e.ctrlKey;
124	  if (mod && e.key.toLowerCase() === 'z') {
125	    e.preventDefault();
126	    if (e.shiftKey) redo();
127	    else undo();
128	    return;
129	  }
130	  if (mod && e.key.toLowerCase() === 'y') {
131	    e.preventDefault();
132	    redo();
133	    return;
134	  }
135	  if ((e.key === 'Delete' || e.key === 'Backspace') && state.selected) {
136	    e.preventDefault();
137	    deleteSelected();
138	    return;
139	  }
140	  if (e.key === 'p') setTool('pen');
141	  else if (e.key === 'w') setTool('width');
142	  else if (e.key === 's') setTool('select');
143	}
144	
145	function setTool(t: Tool) {
146	  state.tool = t;
147	  toolPenBtn.classList.toggle('active', t === 'pen');
148	  toolWidthBtn.classList.toggle('active', t === 'width');
149	  toolSelectBtn.classList.toggle('active', t === 'select');
150	  svg.classList.toggle('tool-select', t === 'select');
151	  if (t !== 'width') brushCursor.style.display = 'none';
152	  if (t !== 'select') deselect();
153	}
154	
155	function penDown(e: PointerEvent) {
156	  pushHistory();
157	  const el = document.createElementNS(SVG_NS, 'path');
158	  el.setAttribute('fill', state.color);
159	  const stroke: Stroke = {
160	    color: state.color,
161	    samples: [sampleFromEvent(e)],
162	    el,
163	    renderMode: 'catmull',
164	  };
165	  el.setAttribute('d', strokeToPathD(stroke));
166	  svg.appendChild(el);
167	  state.strokes.push(stroke);
168	  state.current = stroke;
169	}
170	
171	function penMove(e: PointerEvent) {
172	  if (!state.current) return;
173	  const stroke = state.current;
174	  const events = e.getCoalescedEvents?.() ?? [e];
175	  let changed = false;
176	  for (const ev of events.length > 0 ? events : [e]) {
177	    const sample = sampleFromEvent(ev);
178	    const last = stroke.samples[stroke.samples.length - 1];
179	    if (distance(last, sample) < SAMPLE_MIN_DIST) continue;
180	    stroke.samples.push(sample);
181	    changed = true;
182	  }
183	  if (changed) stroke.el.setAttribute('d', strokeToPathD(stroke));
184	}
185	
186	function selectDown(e: PointerEvent) {
187	  const target = e.target;
188	  if (target instanceof SVGCircleElement) {
189	    const hit = handleByEl.get(target);
190	    if (hit) {
191	      selectStroke(hit.stroke);
192	      pushHistory();
193	      state.draggingNode = {
194	        stroke: hit.stroke,
195	        index: hit.index,
196	        origPositions: hit.stroke.samples.map((s) => ({ x: s.x, y: s.y })),
197	        arcDists: computeArcDistances(hit.stroke.samples, hit.index),
198	        startPoint: canvasPoint(e),
199	      };
200	      svg.classList.add('dragging');
201	      return;
202	    }
203	  }
204	  if (target instanceof SVGPathElement) {
205	    const stroke = state.strokes.find((s) => s.el === target);
206	    if (stroke) {
207	      selectStroke(stroke);
208	      pushHistory();
209	      state.dragging = true;
210	      state.dragLast = canvasPoint(e);
211	      svg.classList.add('dragging');
212	      return;
213	    }
214	  }
215	  deselect();
216	}
217	
218	function selectMove(e: PointerEvent) {
219	  if (state.draggingNode) {
220	    dragNode(state.draggingNode, canvasPoint(e));
221	    return;
222	  }
223	  if (state.dragging && state.selected && state.dragLast) {
224	    const now = canvasPoint(e);
225	    const dx = now.x - state.dragLast.x;
226	    const dy = now.y - state.dragLast.y;
227	    state.dragLast = now;
228	    translateStroke(state.selected, dx, dy);
229	    state.selected.el.setAttribute('d', strokeToPathD(state.selected));
230	    refreshHandlePositions(state.selected);
231	    updateSelectionRect();
232	  }
233	}
234	
235	function selectUp() {
236	  state.dragging = false;
237	  state.dragLast = null;
238	  state.draggingNode = null;
239	  svg.classList.remove('dragging');
240	  if (state.tool !== 'width') brushCursor.style.display = 'none';
241	}
242	
243	function selectStroke(stroke: Stroke) {
244	  if (state.selected === stroke) return;
245	  state.selected = stroke;
246	  buildHandles(stroke);
247	  updateSelectionRect();
248	}
249	
250	function deselect() {
251	  if (!state.selected) return;
252	  state.selected = null;
253	  clearHandles();
254	  updateSelectionRect();
255	}
256	
257	function dragNode(drag: NodeDrag, p: Point) {
258	  const sigma = Math.max(1, state.brushRadius);
259	  const dx = p.x - drag.startPoint.x;
260	  const dy = p.y - drag.startPoint.y;
261	  for (let i = 0; i < drag.stroke.samples.length; i++) {
262	    const weight = Math.exp(-((drag.arcDists[i] / sigma) ** 2));
263	    drag.stroke.samples[i].x = drag.origPositions[i].x + dx * weight;
264	    drag.stroke.samples[i].y = drag.origPositions[i].y + dy * weight;
265	  }
266	  drag.stroke.el.setAttribute('d', strokeToPathD(drag.stroke));
267	  refreshHandlePositions(drag.stroke);
268	  updateSelectionRect();
269	}
270	
271	function computeArcDistances(samples: Sample[], from: number): number[] {
272	  const N = samples.length;
273	  const dists = new Array<number>(N).fill(0);
274	  for (let j = from + 1; j < N; j++) {
275	    dists[j] = dists[j - 1] + distance(samples[j - 1], samples[j]);
276	  }
277	  for (let j = from - 1; j >= 0; j--) {
278	    dists[j] = dists[j + 1] + distance(samples[j + 1], samples[j]);
279	  }
280	  return dists;
281	}
282	
283	function buildHandles(stroke: Stroke) {
284	  clearHandles();
285	  const g = ensureHandleGroup();
286	  for (let i = 0; i < stroke.samples.length; i++) {
287	    const s = stroke.samples[i];
288	    const c = document.createElementNS(SVG_NS, 'circle');
289	    c.setAttribute('cx', String(s.x));
290	    c.setAttribute('cy', String(s.y));
291	    c.setAttribute('r', '4');
292	    c.setAttribute('fill', '#fff');
293	    c.setAttribute('stroke', '#0a84ff');
294	    c.setAttribute('stroke-width', '1.5');
295	    c.setAttribute('class', 'handle');
296	    g.appendChild(c);
297	    handleByEl.set(c, { stroke, index: i });
298	  }
299	}
300	
301	function refreshHandlePositions(stroke: Stroke) {
302	  if (state.selected !== stroke || !handleGroup) return;
303	  const circles = handleGroup.children;
304	  if (circles.length !== stroke.samples.length) {
305	    buildHandles(stroke);
306	    return;
307	  }
308	  for (let i = 0; i < circles.length; i++) {
309	    const c = circles[i] as SVGCircleElement;
310	    c.setAttribute('cx', String(stroke.samples[i].x));
311	    c.setAttribute('cy', String(stroke.samples[i].y));
312	  }
313	}
314	
315	function clearHandles() {
316	  handleByEl.clear();
317	  if (handleGroup) handleGroup.replaceChildren();
318	}
319	
320	function ensureHandleGroup(): SVGGElement {
321	  if (!handleGroup) {
322	    handleGroup = document.createElementNS(SVG_NS, 'g');
323	    handleGroup.setAttribute('id', 'handles');
324	  }
325	  // Re-append so handles stay above strokes drawn after the group was created;
326	  // appendChild moves an existing child to the end rather than duplicating it.
327	  svg.appendChild(handleGroup);
328	  return handleGroup;
329	}
330	
331	function translateStroke(stroke: Stroke, dx: number, dy: number) {
332	  for (const s of stroke.samples) {
333	    s.x += dx;
334	    s.y += dy;
335	  }
336	}
337	
338	function deleteSelected() {
339	  if (!state.selected) return;
340	  pushHistory();
341	  const i = state.strokes.indexOf(state.selected);
342	  if (i >= 0) state.strokes.splice(i, 1);
343	  state.selected.el.remove();
344	  deselect();
345	}
346	
347	function updateSelectionRect() {
348	  if (!state.selected) {
349	    selectionRect.style.display = 'none';
350	    strokeOptions.style.display = 'none';
351	    return;
352	  }
353	  const { minX, minY, maxX, maxY } = strokeBbox(state.selected);
354	  selectionRect.style.display = 'block';
355	  selectionRect.style.left = `${minX}px`;
356	  selectionRect.style.top = `${minY}px`;
357	  selectionRect.style.width = `${maxX - minX}px`;
358	  selectionRect.style.height = `${maxY - minY}px`;
359	  strokeOptions.style.display = 'flex';
360	  strokeOptions.style.left = `${minX}px`;
361	  strokeOptions.style.top = `${maxY + 8}px`;
362	  renderModeRadios.forEach((r) => {
363	    r.checked = r.value === state.selected!.renderMode;
364	  });
365	}
366	
367	function onRenderModeChange(e: Event) {
368	  if (!state.selected) return;
369	  const value = (e.target as HTMLInputElement).value as RenderMode;
370	  if (state.selected.renderMode === value) return;
371	  pushHistory();
372	  state.selected.renderMode = value;
373	  state.selected.el.setAttribute('d', strokeToPathD(state.selected));
374	}
375	
376	function strokeBbox(stroke: Stroke): { minX: number; minY: number; maxX: number; maxY: number } {
377	  let minX = Infinity;
378	  let minY = Infinity;
379	  let maxX = -Infinity;
380	  let maxY = -Infinity;
381	  for (const s of stroke.samples) {
382	    const r = s.w / 2;
383	    if (s.x - r < minX) minX = s.x - r;
384	    if (s.x + r > maxX) maxX = s.x + r;
385	    if (s.y - r < minY) minY = s.y - r;
386	    if (s.y + r > maxY) maxY = s.y + r;
387	  }
388	  return { minX, minY, maxX, maxY };
389	}
390	
391	function widthDown(e: PointerEvent) {
392	  pushHistory();
393	  state.brushing = true;
394	  applyBrush(canvasPoint(e), e.shiftKey);
395	}
396	
397	function widthMove(e: PointerEvent) {
398	  if (!state.brushing) return;
399	  applyBrush(canvasPoint(e), e.shiftKey);
400	}
401	
402	function applyBrush(p: Point, shrink: boolean) {
403	  const delta = shrink ? -BRUSH_STRENGTH : BRUSH_STRENGTH;
404	  for (const stroke of state.strokes) {
405	    let touched = false;
406	    for (const s of stroke.samples) {
407	      const d = distance(p, s);
408	      if (d > state.brushRadius) continue;
409	      const falloff = 1 - d / state.brushRadius;
410	      s.w = clamp(s.w + delta * falloff, MIN_WIDTH, MAX_WIDTH);
411	      touched = true;
412	    }
413	    if (touched) stroke.el.setAttribute('d', strokeToPathD(stroke));
414	  }
415	}
416	
417	function updateBrushCursor(e: PointerEvent) {
418	  const visible = state.tool === 'width' || state.draggingNode !== null;
419	  if (!visible) {
420	    brushCursor.style.display = 'none';
421	    return;
422	  }
423	  const size = state.brushRadius * 2;
424	  brushCursor.style.display = 'block';
425	  brushCursor.style.left = `${e.clientX}px`;
426	  brushCursor.style.top = `${e.clientY}px`;
427	  brushCursor.style.width = `${size}px`;
428	  brushCursor.style.height = `${size}px`;
429	}
430	
431	function sampleFromEvent(e: PointerEvent): Sample {
432	  const { x, y } = canvasPoint(e);
433	  return { x, y, w: effectiveWidth(e) };
434	}
435	
436	function canvasPoint(e: PointerEvent): Point {
437	  const rect = svg.getBoundingClientRect();
438	  return { x: e.clientX - rect.left, y: e.clientY - rect.top };
439	}
440	
441	function effectiveWidth(e: PointerEvent): number {
442	  const hasPressure = e.pointerType !== 'mouse' && e.pressure > 0 && e.pressure !== 0.5;
443	  return hasPressure ? state.baseWidth * e.pressure * 2 : state.baseWidth;
444	}
445	
446	function strokeToPathD(stroke: Stroke): string {
447	  const { samples } = stroke;
448	  if (samples.length === 0) return '';
449	  if (samples.length === 1) return dotPath(samples[0]);
450	  return ribbonPath(stroke);
451	}
452	
453	function dotPath(s: Sample): string {
454	  const r = s.w / 2;
455	  return (
456	    `M ${s.x - r} ${s.y}` +
457	    ` A ${r} ${r} 0 1 0 ${s.x + r} ${s.y}` +
458	    ` A ${r} ${r} 0 1 0 ${s.x - r} ${s.y} Z`
459	  );
460	}
461	
462	function ribbonPath(stroke: Stroke): string {
463	  const samples = stroke.samples;
464	  const { left, right } = offsetRails(samples);
465	  const startR = samples[0].w / 2;
466	  const endR = samples[samples.length - 1].w / 2;
467	  const reversedRight = [...right].reverse();
468	  const smooth = stroke.renderMode === 'catmull' ? smoothRailCatmull : smoothRailQuadratic;
469	  const parts: string[] = [`M ${left[0].x} ${left[0].y}`];
470	  parts.push(smooth(left));
471	  parts.push(`A ${endR} ${endR} 0 0 0 ${right[right.length - 1].x} ${right[right.length - 1].y}`);
472	  parts.push(smooth(reversedRight));
473	  parts.push(`A ${startR} ${startR} 0 0 0 ${left[0].x} ${left[0].y}`);
474	  parts.push('Z');
475	  return parts.join(' ');
476	}
477	
478	function smoothRailCatmull(pts: Point[]): string {
479	  if (pts.length < 2) return '';
480	  if (pts.length === 2) return `L ${pts[1].x} ${pts[1].y}`;
481	  const cmds: string[] = [];
482	  const n = pts.length;
483	  for (let i = 0; i < n - 1; i++) {
484	    const p0 = i > 0 ? pts[i - 1] : pts[i];
485	    const p1 = pts[i];
486	    const p2 = pts[i + 1];
487	    const p3 = i + 2 < n ? pts[i + 2] : pts[i + 1];
488	    const c1x = p1.x + (p2.x - p0.x) / 6;
489	    const c1y = p1.y + (p2.y - p0.y) / 6;
490	    const c2x = p2.x - (p3.x - p1.x) / 6;
491	    const c2y = p2.y - (p3.y - p1.y) / 6;
492	    cmds.push(`C ${c1x} ${c1y} ${c2x} ${c2y} ${p2.x} ${p2.y}`);
493	  }
494	  return cmds.join(' ');
495	}
496	
497	function smoothRailQuadratic(pts: Point[]): string {
498	  if (pts.length < 2) return '';
499	  if (pts.length === 2) return `L ${pts[1].x} ${pts[1].y}`;
500	  const cmds: string[] = [];
501	  const m0x = (pts[0].x + pts[1].x) / 2;
502	  const m0y = (pts[0].y + pts[1].y) / 2;
503	  cmds.push(`L ${m0x} ${m0y}`);
504	  for (let i = 1; i < pts.length - 1; i++) {
505	    const mx = (pts[i].x + pts[i + 1].x) / 2;
506	    const my = (pts[i].y + pts[i + 1].y) / 2;
507	    cmds.push(`Q ${pts[i].x} ${pts[i].y} ${mx} ${my}`);
508	  }
509	  cmds.push(`L ${pts[pts.length - 1].x} ${pts[pts.length - 1].y}`);
510	  return cmds.join(' ');
511	}
512	
513	function offsetRails(samples: Sample[]): { left: Point[]; right: Point[] } {
514	  const normals = smoothedNormals(samples);
515	  const left: Point[] = [];
516	  const right: Point[] = [];
517	  for (let i = 0; i < samples.length; i++) {
518	    const half = samples[i].w / 2;
519	    left.push({ x: samples[i].x + normals[i].x * half, y: samples[i].y + normals[i].y * half });
520	    right.push({ x: samples[i].x - normals[i].x * half, y: samples[i].y - normals[i].y * half });
521	  }
522	  return { left, right };
523	}
524	
525	function smoothedNormals(samples: Sample[]): Point[] {
526	  const raw = rawNormals(samples);
527	  if (raw.length <= 2) return raw;
528	  const smoothed: Point[] = new Array(raw.length);
529	  smoothed[0] = raw[0];
530	  smoothed[raw.length - 1] = raw[raw.length - 1];
531	  for (let i = 1; i < raw.length - 1; i++) {
532	    const nx = raw[i - 1].x + raw[i].x + raw[i + 1].x;
533	    const ny = raw[i - 1].y + raw[i].y + raw[i + 1].y;
534	    const len = Math.hypot(nx, ny) || 1;
535	    smoothed[i] = { x: nx / len, y: ny / len };
536	  }
537	  return smoothed;
538	}
539	
540	function rawNormals(samples: Sample[]): Point[] {
541	  const normals: Point[] = [];
542	  for (let i = 0; i < samples.length; i++) {
543	    const prev = samples[i - 1] ?? samples[i];
544	    const next = samples[i + 1] ?? samples[i];
545	    const tx = next.x - prev.x;
546	    const ty = next.y - prev.y;
547	    const len = Math.hypot(tx, ty) || 1;
548	    normals.push({ x: -ty / len, y: tx / len });
549	  }
550	  return normals;
551	}
552	
553	function distance(a: Point, b: Point): number {
554	  return Math.hypot(a.x - b.x, a.y - b.y);
555	}
556	
557	function clamp(v: number, lo: number, hi: number): number {
558	  return v < lo ? lo : v > hi ? hi : v;
559	}
560	
561	function syncCanvasSize() {
562	  const w = window.innerWidth;
563	  const h = window.innerHeight;
564	  svg.setAttribute('viewBox', `0 0 ${w} ${h}`);
565	  svg.setAttribute('width', String(w));
566	  svg.setAttribute('height', String(h));
567	}
568	
569	function clearAll() {
570	  pushHistory();
571	  deselect();
572	  state.strokes = [];
573	  while (svg.firstChild) svg.removeChild(svg.firstChild);
574	}
575	
576	function pushHistory() {
577	  undoStack.push(snapshot());
578	  if (undoStack.length > MAX_HISTORY) undoStack.shift();
579	  redoStack.length = 0;
580	  updateHistoryButtons();
581	}
582	
583	function undo() {
584	  const snap = undoStack.pop();
585	  if (!snap) return;
586	  redoStack.push(snapshot());
587	  restore(snap);
588	  updateHistoryButtons();
589	}
590	
591	function redo() {
592	  const snap = redoStack.pop();
593	  if (!snap) return;
594	  undoStack.push(snapshot());
595	  restore(snap);
596	  updateHistoryButtons();
597	}
598	
599	function updateHistoryButtons() {
600	  undoBtn.disabled = undoStack.length === 0;
601	  redoBtn.disabled = redoStack.length === 0;
602	}
603	
604	function snapshot(): Snapshot {
605	  return state.strokes.map((s) => ({
606	    color: s.color,
607	    renderMode: s.renderMode,
608	    samples: s.samples.map((p) => ({ x: p.x, y: p.y, w: p.w })),
609	  }));
610	}
611	
612	function restore(snap: Snapshot) {
613	  deselect();
614	  state.strokes = [];
615	  while (svg.firstChild) svg.removeChild(svg.firstChild);
616	  for (const data of snap) {
617	    const el = document.createElementNS(SVG_NS, 'path');
618	    el.setAttribute('fill', data.color);
619	    const stroke: Stroke = {
620	      color: data.color,
621	      samples: data.samples,
622	      el,
623	      renderMode: data.renderMode,
624	    };
625	    el.setAttribute('d', strokeToPathD(stroke));
626	    svg.appendChild(el);
627	    state.strokes.push(stroke);
628	  }
629	}
630	
631	function exportSvg() {
632	  const clone = svg.cloneNode(true) as SVGSVGElement;
633	  clone.removeAttribute('id');
634	  clone.setAttribute('xmlns', SVG_NS);
635	  clone.querySelector('#handles')?.remove();
636	  triggerDownload(
637	    new Blob([clone.outerHTML], { type: 'image/svg+xml' }),
638	    `painting-${Date.now()}.svg`,
639	  );
640	}
641	
642	function saveFile() {
643	  const data = { version: FILE_VERSION, strokes: snapshot() };
644	  triggerDownload(
645	    new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' }),
646	    `painting-${Date.now()}.json`,
647	  );
648	}
649	
650	function loadFile() {
651	  const input = document.createElement('input');
652	  input.type = 'file';
653	  input.accept = 'application/json,.json';
654	  input.addEventListener('change', () => {
655	    const file = input.files?.[0];
656	    if (!file) return;
657	    file.text().then(loadFromText).catch(reportLoadError);
658	  });
659	  input.click();
660	}
661	
662	function loadFromText(text: string) {
663	  try {
664	    const data = JSON.parse(text) as unknown;
665	    const snap = migrate(data);
666	    undoStack.length = 0;
667	    redoStack.length = 0;
668	    restore(snap);
669	    updateHistoryButtons();
670	  } catch (err) {
671	    reportLoadError(err);
672	  }
673	}
674	
675	function migrate(data: unknown): Snapshot {
676	  if (!data || typeof data !== 'object') throw new Error('file is not a JSON object');
677	  const obj = data as { version?: unknown; strokes?: unknown };
678	  if (obj.version !== 1) throw new Error(`unsupported file version: ${String(obj.version)}`);
679	  if (!Array.isArray(obj.strokes)) throw new Error('strokes field is missing or not an array');
680	  return obj.strokes.map(parseStrokeV1);
681	}
682	
683	function parseStrokeV1(s: unknown): Snapshot[number] {
684	  if (!s || typeof s !== 'object') throw new Error('stroke must be an object');
685	  const obj = s as { color?: unknown; renderMode?: unknown; samples?: unknown };
686	  if (typeof obj.color !== 'string') throw new Error('stroke.color must be a string');
687	  if (obj.renderMode !== 'catmull' && obj.renderMode !== 'quadratic') {
688	    throw new Error(`unknown renderMode: ${String(obj.renderMode)}`);
689	  }
690	  if (!Array.isArray(obj.samples)) throw new Error('stroke.samples must be an array');
691	  return {
692	    color: obj.color,
693	    renderMode: obj.renderMode,
694	    samples: obj.samples.map(parseSampleV1),
695	  };
696	}
697	
698	function parseSampleV1(s: unknown): Sample {
699	  if (!s || typeof s !== 'object') throw new Error('sample must be an object');
700	  const obj = s as { x?: unknown; y?: unknown; w?: unknown };
701	  if (typeof obj.x !== 'number' || typeof obj.y !== 'number' || typeof obj.w !== 'number') {
702	    throw new Error('sample fields x, y, w must be numbers');
703	  }
704	  return { x: obj.x, y: obj.y, w: obj.w };
705	}
706	
707	function reportLoadError(err: unknown) {
708	  alert(`Failed to load: ${err instanceof Error ? err.message : String(err)}`);
709	}
710	
711	function triggerDownload(blob: Blob, filename: string) {
712	  const url = URL.createObjectURL(blob);
713	  const a = document.createElement('a');
714	  a.href = url;
715	  a.download = filename;
716	  document.body.appendChild(a);
717	  a.click();
718	  document.body.removeChild(a);
719	  URL.revokeObjectURL(url);
720	}
