:root {
  color-scheme: light;
  font-family: system-ui, sans-serif;
  color: #222;
}

html, body {
  margin: 0;
  height: 100%;
  overflow: hidden;
  background: #f5f5f5;
}

#canvas {
  position: fixed;
  inset: 0;
  width: 100vw;
  height: 100vh;
  touch-action: none;
  cursor: crosshair;
  background: #ffffff;
}

#brush-cursor {
  position: fixed;
  pointer-events: none;
  border: 1.5px dashed #666;
  border-radius: 50%;
  transform: translate(-50%, -50%);
  display: none;
  box-sizing: border-box;
}

#selection-rect {
  position: fixed;
  pointer-events: none;
  border: 1.5px dashed #0a84ff;
  display: none;
  box-sizing: border-box;
}

#canvas.tool-select {
  cursor: default;
}

#canvas.tool-select.dragging {
  cursor: grabbing;
}

.handle {
  cursor: move;
}

#stroke-options {
  position: fixed;
  pointer-events: auto;
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(6px);
  border: 1px solid #ddd;
  border-radius: 6px;
  padding: 6px 10px;
  font-size: 12px;
  display: none;
  gap: 10px;
  align-items: center;
  color: #222;
  user-select: none;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.06);
}

#stroke-options label {
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

#stroke-options .label {
  color: #888;
}

#toolbar {
  position: fixed;
  top: 12px;
  left: 12px;
  display: flex;
  gap: 12px;
  align-items: center;
  padding: 8px 12px;
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(6px);
  border: 1px solid #ddd;
  border-radius: 8px;
  font-size: 13px;
  color: #222;
  user-select: none;
}

#toolbar label {
  display: flex;
  align-items: center;
  gap: 6px;
}

#toolbar button {
  font: inherit;
  padding: 4px 10px;
  border: 1px solid #ccc;
  background: #fafafa;
  border-radius: 4px;
  cursor: pointer;
  color: inherit;
}

#toolbar button:hover {
  background: #efefef;
}

#toolbar .tools {
  display: flex;
  gap: 4px;
}

#toolbar .tool.active {
  background: #222;
  color: #fff;
  border-color: #222;
}

#toolbar .icon-btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 4px 6px;
}

#toolbar button:disabled {
  opacity: 0.35;
  cursor: default;
}

#toolbar button:disabled:hover {
  background: #fafafa;
}

