type Point = { x: number; y: number };
type Sample = Point & { w: number };
type Stroke = { color: string; samples: Sample[] };

const DEFAULT_COLOR = '#222222';
const DEFAULT_BASE_WIDTH = 12;

export class Painter {
  private strokes: Stroke[] = [];
  private current: Stroke | null = null;
  private color = DEFAULT_COLOR;
  private baseWidth = DEFAULT_BASE_WIDTH;

  penDown(point: Point) {
    const stroke: Stroke = { color: this.color, samples: [this.sample(point)] };
    this.strokes.push(stroke);
    this.current = stroke;
  }

  penUp() {
    this.current = null;
  }

  get svgContent(): string {
    return this.strokes.map((s) => this.renderStroke(s)).join('');
  }

  get menuState() {
    return {
      tool: 'pen',
      canUndo: false,
      canRedo: false,
      selection: null,
    };
  }

  private sample(point: Point): Sample {
    return { x: point.x, y: point.y, w: this.baseWidth };
  }

  private renderStroke(stroke: Stroke): string {
    return `<path fill="${stroke.color}" d="${strokeToPathD(stroke)}"/>`;
  }
}

function strokeToPathD(stroke: Stroke): string {
  const { samples } = stroke;
  if (samples.length === 0) return '';
  return dotPath(samples[0]);
}

function dotPath(s: Sample): string {
  const r = s.w / 2;
  return (
    `M ${s.x - r} ${s.y}` +
    ` A ${r} ${r} 0 1 0 ${s.x + r} ${s.y}` +
    ` A ${r} ${r} 0 1 0 ${s.x - r} ${s.y} Z`
  );
}

